import React from "react";
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from "react-router-dom";
import './App.css';

export default function App() {
  return (
    <Router>
      <div>
        <nav>
          <ul>
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/login">Login</Link>
            </li>
            <li>
              <Link to="/reset">Reset</Link>
            </li>
            <li>
              <Link to="/dashboard">Dashboard</Link>
            </li>
          </ul>
        </nav>

        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/reset" element={<PasswordReset />} />
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/new/:id" element={<NewPage />} /> {/* Добавьте этот маршрут, если его еще нет */}
        </Routes>
      </div>
    </Router>
  );
}

function Home() {
  return <h2 style={{textAlign: 'center'}}>Home</h2>;
}

function Login() {
  const navigate = useNavigate();
  const id = "123"; // Пример ID, можете заменить на реальное значение

  return (
    <div>
      <h2 style={{textAlign: 'center'}}>Login</h2>
      <input placeholder="Email" />
      <input placeholder="Password" />
      <button className="btn-signup">SignUp</button>
      <button 
        className="btn-register"
        onClick={async (event) => { 
          await navigate(`/new/${id}`); 
        }}
      >
        Register
      </button>
    </div>
  );
}

function PasswordReset() {
  return <h2 style={{textAlign: 'center'}}>Password Reset</h2>;
}

function Dashboard() {
  return <h2 style={{textAlign: 'center'}}>Dashboard</h2>;
}

// Добавьте этот компонент, если его еще нет
function NewPage() {
  return <h2 style={{textAlign: 'center'}}>New Page</h2>;
}
